function solve(n) {
    function convertToBase(num, base) {
        if (num === 0) return '0';
        let digits = [];
        while (num > 0) {
            let remainder = num % base;
            if (remainder < 10) {
                digits.push(remainder.toString());
            } else {
                digits.push(String.fromCharCode(65 + remainder - 10));
            }
            num = Math.floor(num / base);
        }
        return digits.reverse().join('');
    }
    let n2 = n * n;
    let n3 = n * n * n;
    let hexPart = convertToBase(n2, 16);
    let base36Part = convertToBase(n3, 36);
    return hexPart + base36Part;
}
